import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Ads Reporting FAQ","description":"","frontmatter":{"title":"Ads Reporting FAQ","slug":"ads-reporting-faq"},"headers":[],"relativePath":"marketer-hub/ads-reporting-faq.md","filePath":"marketer-hub/ads-reporting-faq.md"}'),n={name:"marketer-hub/ads-reporting-faq.md"};function s(i,e,l,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<p>The most frequently asked questions about ads reporting.</p><details><summary>What does “deeplink\\_no\\_attribution=true” mean? Should I change it to false for attribution to work?</summary><p>This flag is used to disable deep link attribution thus allowing us to do normal SAN attribution. SAN partners like Google AdWords/Facebook integration are different from conventional non-SAN partners, where we send conversion data to SAN partners and they will claim the install/events according to their conversion logic and respond to us via API. Branch then analyzes the data from all the partners and attributes the same install/event based on last-touch attribution logic. You will see less data in Branch as we show only attributed data for a SAN partner than the respective SAN dashboard.</p></details><details><summary>What is the difference between Day 0 and Day 1?</summary><p>Day 0 is the day on the install, and Day 1 is the following day, and so on.</p><p>Branch tracks install as the first open of the app. The second open on the same day is coined as OPEN, which is taken into consideration for the cohort retention report. That is why it does not show as 100%. The other days will be considered the first open on that particular day.</p></details><details><summary>Why am I unable to view stats for links created through the API?</summary><p>Individually checking stats for API/SDK created links is currently not possible. As a workaround, if you have appended custom analytical labels or tags to the link data, you can view the analytics on the <a href="https://dashboard.branch.io/sources" target="_blank" rel="noreferrer">Sources</a> page with the corresponding tag added as a filter.</p></details><details><summary>Where is the complete list of country names and country code values?</summary><p>Branch does not maintain the Country Name and Country Code list, we use MaxMind for geo-lookup from IP. You can enter an IP <a href="https://www.maxmind.com/en/home" target="_blank" rel="noreferrer">here</a> to see how MaxMind will interpret this and which country it will associate the IP with. The country codes will be in ISO-3166-2 format.</p></details><details><summary>Are my ad campaign installs only drive by clicks?</summary><p>On campaigns with Impression links enabled you will also see installs that are driven by Impressions. Include the Impressions column on Branch Analytics with clicks to see the complete picture.</p></details><details><summary>How can I pull postback logs?</summary><p>You can use the Custom Exports <a href="https://branch.dashboard.branch.io/custom-exports" target="_blank" rel="noreferrer">section</a> of the Branch Dashboard to pull postback logs.</p><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><p>Configure the export in the following way:</p><p><strong>Topic</strong>: Postback Records</p><p><strong>Columns</strong>: Choose all columns starting with <code>webhook</code></p><p><strong>Filters</strong>: You can apply the <code>webhook</code> filter for <code>Webhook Partner Key</code> equals <code>di_adobe_analytics</code> (if you wish to pull the data from a Data Integration Partner like adobe).</p><p>Or <code>Webhook Partner Key</code> equals <code>a_inmobi</code> (If you wish to pull the data from an Ad Partner like Inmobi).</p><p>The 3p value <code>a_inmobi</code> can be found in the Partner Management section of the Ad Partner as the &quot;Partner Identifier&quot; value.</p><h3 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h3><p>Access to the Custom Exports feature is included in our Engagement and Performance <a href="./packaging.html">products</a>.</p></details>',7)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
